+            timestamp: SystemTime::now()
+                .duration_since(UNIX_EPOCH)
+                .unwrap()
+                .as_secs(),
+            healthy: problems_found == 0,
+            problems_found,
+            remediations_triggered,
+            outcomes,
+            metrics: if config.collect_metrics {
+                Some(metrics.to_json())
+            } else {
